 * Prints a greeting followed by the supplied names.
 * Each name is separated by a comma and a space, just like the
 * original Python implementation (including a trailing comma).
 *
 * @param names – any number of string arguments
 */
function greet(...names: string[]): void {
  // Write the leading part without a newline
  process.stdout.write('Hello ');

  // Append each name followed by ", "
  for (const name of names) {
    process.stdout.write(`${name}, `);
  }

  // Finally emit a newline so the next console output starts on a new line
  process.stdout.write('\n');
}

